            model: "gemini-1.5-flash",
            contents: [{ role: "user", parts: [{ text: "Hi" }] }],
        });
        console.log("Success (1.5):", res.text);
    } catch (e) {
        console.error("Failed (1.5):", e.message || e);
    }
